// SHARED HOOK: CURRENCY TOGGLE (USD ↔ PHP)
// Persists user's currency preference + FX rate across the entire toolkit
// ═══════════════════════════════════════════════════════════════════
const DEFAULT_FX_RATE = 56.5; // USD to PHP, sensible May 2026 default

function useCurrency() {
  const [currency, setCurrency] = useState('USD');
  const [fxRate, setFxRate] = useState(DEFAULT_FX_RATE);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const c = await window.storage.get('currency:pref');
        if (c?.value) setCurrency(c.value);
        const r = await window.storage.get('currency:rate');
        if (r?.value) setFxRate(Number(r.value) || DEFAULT_FX_RATE);
      } catch {}
      setLoaded(true);
    })();
  }, []);
  useEffect(() => { if (loaded) window.storage.set('currency:pref', currency).catch(()=>{}); }, [currency, loaded]);
  useEffect(() => { if (loaded) window.storage.set('currency:rate', String(fxRate)).catch(()=>{}); }, [fxRate, loaded]);

  // Convert USD value to display currency
  const convert = (usd) => currency === 'PHP' ? Number(usd) * Number(fxRate) : Number(usd);

  // Format with currency symbol
  const fmt = (usd, decimals = 0) => {
    const val = convert(usd);
    const symbol = currency === 'PHP' ? '₱' : '$';
    return symbol + val.toLocaleString('en-US', { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
  };

  // Format with 2 decimals
  const fmt2 = (usd) => fmt(usd, 2);

  return { currency, setCurrency, fxRate, setFxRate, convert, fmt, fmt2 };
}

// Reusable inline currency selector UI
function CurrencyToggle({ currency, setCurrency, fxRate, setFxRate, compact }) {
  return (
    <div className={`flex items-center gap-2 ${compact ? '' : 'p-3 rounded-xl bg-white border border-slate-200'}`}>
      <div className="text-[10px] uppercase tracking-wider font-bold text-slate-500">Currency</div>
      <div className="flex gap-1">
        <button onClick={() => setCurrency('USD')}
          className={`px-3 py-1 rounded-md text-xs font-bold transition ${currency === 'USD' ? 'text-white shadow' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
          style={currency === 'USD' ? { background: ROYAL } : {}}>
          $ USD
        </button>
        <button onClick={() => setCurrency('PHP')}
          className={`px-3 py-1 rounded-md text-xs font-bold transition ${currency === 'PHP' ? 'text-white shadow' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
          style={currency === 'PHP' ? { background: ROYAL } : {}}>
          ₱ PHP
        </button>
      </div>
      <div className="flex items-center gap-1 text-xs text-slate-500">
        <span>1 USD =</span>
        <input type="number" step="0.1" value={fxRate} onChange={e => setFxRate(Number(e.target.value) || DEFAULT_FX_RATE)}
          className="w-16 px-2 py-0.5 rounded border border-slate-300 text-xs text-right font-mono" />
        <span>PHP</span>
      </div>
    </div>
  );
}

