// ═══════════════════════════════════════════════════════════════════
// COMPONENT: DEPRECIATION CALCULATOR
// ═══════════════════════════════════════════════════════════════════

function Depreciation() {
  const [assetName, setAssetName] = useState('Office Equipment');
  const [cost, setCost] = useState('10000');
  const [salvage, setSalvage] = useState('1000');
  const [life, setLife] = useState('5');
  const [method, setMethod] = useState('Straight-Line');
  const [placedIn, setPlacedIn] = useState('2026-01-01');
  const [schedule, setSchedule] = useState([]);

  const calc = () => {
    const c = parseFloat(cost) || 0;
    const s = parseFloat(salvage) || 0;
    const l = parseInt(life) || 1;
    const depreciableBase = c - s;
    let book = c;
    const rows = [];

    if (method === 'Straight-Line') {
      const annual = depreciableBase / l;
      for (let y = 1; y <= l; y++) {
        const dep = annual;
        book -= dep;
        rows.push({ year: y, beginBook: book + dep, dep, accumDep: c - book, endBook: book });
      }
    } else if (method === 'Double-Declining Balance') {
      const rate = 2 / l;
      let accum = 0;
      for (let y = 1; y <= l; y++) {
        let dep = Math.max(0, book * rate);
        // Don't depreciate below salvage
        if (book - dep < s) dep = book - s;
        // In the final year, take remaining depreciation
        if (y === l) dep = book - s;
        accum += dep;
        const beginBook = book;
        book -= dep;
        rows.push({ year: y, beginBook, dep, accumDep: accum, endBook: book });
      }
    } else if (method === 'Sum-of-Years Digits') {
      const SYD = (l * (l + 1)) / 2;
      let accum = 0;
      for (let y = 1; y <= l; y++) {
        const factor = (l - y + 1) / SYD;
        const dep = depreciableBase * factor;
        accum += dep;
        const beginBook = book;
        book -= dep;
        rows.push({ year: y, beginBook, dep, accumDep: accum, endBook: book });
      }
    } else if (method === 'MACRS (5-Year)') {
      // IRS MACRS 5-year half-year convention percentages
      const macrs = [0.20, 0.32, 0.192, 0.1152, 0.1152, 0.0576];
      let accum = 0;
      for (let y = 0; y < macrs.length; y++) {
        const dep = c * macrs[y]; // MACRS doesn't use salvage
        accum += dep;
        const beginBook = book;
        book -= dep;
        rows.push({ year: y + 1, beginBook, dep, accumDep: accum, endBook: book });
      }
    } else if (method === 'MACRS (7-Year)') {
      const macrs = [0.1429, 0.2449, 0.1749, 0.1249, 0.0893, 0.0892, 0.0893, 0.0446];
      let accum = 0;
      for (let y = 0; y < macrs.length; y++) {
        const dep = c * macrs[y];
        accum += dep;
        const beginBook = book;
        book -= dep;
        rows.push({ year: y + 1, beginBook, dep, accumDep: accum, endBook: book });
      }
    } else if (method === 'Section 179 (Full Expense)') {
      rows.push({ year: 1, beginBook: c, dep: c, accumDep: c, endBook: 0 });
    }

    setSchedule(rows);
  };

  const exportCSV = () => {
    const header = ['Year', 'Beginning Book Value', 'Depreciation Expense', 'Accumulated Depreciation', 'Ending Book Value'];
    const csv = [header, ...schedule.map(r => [r.year, r.beginBook.toFixed(2), r.dep.toFixed(2), r.accumDep.toFixed(2), r.endBook.toFixed(2)])]
      .map(row => row.map(c => `"${c}"`).join(','))
      .join('\n');
    downloadFile(csv, `depreciation_${assetName.replace(/\s/g, '_')}.csv`, 'text/csv');
  };

  const totalDep = schedule.reduce((s, r) => s + r.dep, 0);

  return (
    <div>
      <div style={{ background: SHEEN }} className="glass-card p-7 rounded-2xl mt-6">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          <div>
            <label className="text-xs uppercase tracking-wider font-bold text-slate-600 block mb-2">Asset Name</label>
            <input value={assetName} onChange={e => setAssetName(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm font-medium focus:border-blue-500 focus:ring-2 focus:ring-blue-200 outline-none" />
          </div>
          <div>
            <label className="text-xs uppercase tracking-wider font-bold text-slate-600 block mb-2">Cost / Basis ($)</label>
            <input type="number" step="0.01" value={cost} onChange={e => setCost(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm font-mono focus:border-blue-500 outline-none" />
          </div>
          <div>
            <label className="text-xs uppercase tracking-wider font-bold text-slate-600 block mb-2">Salvage Value ($)</label>
            <input type="number" step="0.01" value={salvage} onChange={e => setSalvage(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm font-mono focus:border-blue-500 outline-none" />
            <div className="text-[10px] text-slate-400 mt-1">Not used for MACRS or Section 179</div>
          </div>
          <div>
            <label className="text-xs uppercase tracking-wider font-bold text-slate-600 block mb-2">Useful Life (years)</label>
            <input type="number" value={life} onChange={e => setLife(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm font-mono focus:border-blue-500 outline-none" />
            <div className="text-[10px] text-slate-400 mt-1">Ignored for MACRS (fixed schedules)</div>
          </div>
          <div>
            <label className="text-xs uppercase tracking-wider font-bold text-slate-600 block mb-2">Placed in Service</label>
            <input type="date" value={placedIn} onChange={e => setPlacedIn(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm font-mono focus:border-blue-500 outline-none" />
          </div>
          <div>
            <label className="text-xs uppercase tracking-wider font-bold text-slate-600 block mb-2">Depreciation Method</label>
            <select value={method} onChange={e => setMethod(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm font-medium focus:border-blue-500 outline-none">
              <option>Straight-Line</option>
              <option>Double-Declining Balance</option>
              <option>Sum-of-Years Digits</option>
              <option>MACRS (5-Year)</option>
              <option>MACRS (7-Year)</option>
              <option>Section 179 (Full Expense)</option>
            </select>
          </div>
        </div>

        <button onClick={calc}
          className="sheen-btn mt-5 text-white font-bold py-3 px-8 rounded-xl shadow-lg text-sm tracking-wide flex items-center gap-2">
          <Calculator size={16} /> Calculate Depreciation Schedule
        </button>
      </div>

      {schedule.length > 0 && (
        <div className="mt-8 fade-in">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-5">
            <SummaryCard label="Asset" value={assetName} sub={`Placed in ${placedIn}`} />
            <SummaryCard label="Method" value={method} sub={`${schedule.length}-year schedule`} />
            <SummaryCard label="Total Depreciation" value={`$${totalDep.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}`} sub={`${((totalDep / parseFloat(cost || 1)) * 100).toFixed(1)}% of cost`} highlight />
            <SummaryCard label="Final Book Value" value={`$${schedule[schedule.length - 1].endBook.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}`} sub="End of life" />
          </div>

          <div className="flex justify-between items-center mb-3">
            <div style={{ color: NAVY, fontFamily: fontDisplay }} className="text-xl font-bold">Annual Depreciation Schedule</div>
            <button onClick={exportCSV}
              className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-white border border-slate-300 hover:border-blue-400 transition text-sm font-semibold text-slate-700 shadow-sm">
              <Download size={16} /> Export CSV
            </button>
          </div>

          <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-lg">
            <table className="w-full text-sm">
              <thead style={{ background: NAVY }} className="text-white">
                <tr>
                  <th className="text-left px-4 py-3 text-xs uppercase tracking-wider font-semibold">Year</th>
                  <th className="text-right px-4 py-3 text-xs uppercase tracking-wider font-semibold">Beginning Book Value</th>
                  <th className="text-right px-4 py-3 text-xs uppercase tracking-wider font-semibold">Depreciation Expense</th>
                  <th className="text-right px-4 py-3 text-xs uppercase tracking-wider font-semibold">Accumulated Depreciation</th>
                  <th className="text-right px-4 py-3 text-xs uppercase tracking-wider font-semibold">Ending Book Value</th>
                </tr>
              </thead>
              <tbody>
                {schedule.map((r, i) => (
                  <tr key={i} className={i % 2 ? 'bg-slate-50' : 'bg-white'}>
                    <td className="px-4 py-2.5 font-mono text-sm font-bold" style={{ color: ROYAL }}>Year {r.year}</td>
                    <td className="px-4 py-2.5 text-right font-mono text-sm text-slate-700">${r.beginBook.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</td>
                    <td className="px-4 py-2.5 text-right font-mono text-sm font-bold text-red-600">${r.dep.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</td>
                    <td className="px-4 py-2.5 text-right font-mono text-sm text-slate-600">${r.accumDep.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</td>
                    <td className="px-4 py-2.5 text-right font-mono text-sm font-bold text-slate-800">${r.endBook.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <div className="mt-6 p-5 rounded-2xl border-l-4" style={{ background: '#F0F9FF', borderColor: GOLD }}>
            <div className="flex gap-3">
              <Lightbulb size={20} style={{ color: GOLD }} className="flex-shrink-0 mt-0.5" />
              <div>
                <div className="font-bold text-blue-900 mb-1 text-sm uppercase tracking-wider">ProAdvisor Note</div>
                <div className="text-blue-900 text-sm leading-relaxed">
                  Book depreciation (what you record in QBO) often differs from tax depreciation (what's on the return). Many bookkeepers keep books on Straight-Line for clean financials and let the CPA convert to MACRS/Section 179 for the tax return via a Schedule M-1 adjustment. Always confirm the method with the client's tax preparer before posting monthly entries. In QBO: monthly journal entry → Debit Depreciation Expense, Credit Accumulated Depreciation.
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

