function USTax101() {
  const [active, setActive] = useState('federalbasics');
  const topic = US_TAX_TOPICS.find(t => t.id === active);

  return (
    <div>
      <SectionHead eyebrow="Training & Skills · Tool" title="US Tax 101 for Bookkeepers" desc="Bookkeepers don't file tax returns — but every entry you make affects one. Master these eight topics and you stop being a data-entry clerk and start being a value-adding partner to the CPA." />

      <div style={{ background: SHEEN }} className="glass-card p-5 rounded-2xl mt-6 mb-5">
        <div className="flex gap-3 items-start">
          <AlertTriangle size={20} style={{ color: ROYAL }} className="flex-shrink-0 mt-0.5" />
          <div className="text-sm text-slate-700 leading-relaxed">
            <span className="font-bold" style={{ color: NAVY }}>Important disclaimer:</span> This is educational content for bookkeepers — not tax advice for clients. Always refer clients to a licensed CPA or EA for filing decisions. Bookkeepers prepare the data; CPAs interpret it for the IRS.
          </div>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-2 mb-6">
        {US_TAX_TOPICS.map(t => {
          const isActive = active === t.id;
          return (
            <button key={t.id} onClick={() => setActive(t.id)}
              className={`p-3 rounded-2xl transition text-left ${isActive ? 'text-white shadow-lg' : 'bg-white border border-slate-200 hover:border-blue-300'}`}
              style={isActive ? { background: `linear-gradient(135deg, ${ROYAL} 0%, ${CYAN} 100%)` } : {}}>
              <div className="text-2xl mb-1">{t.icon}</div>
              <div className={`text-xs font-bold leading-tight ${isActive ? 'text-white' : 'text-slate-800'}`}>{t.title}</div>
            </button>
          );
        })}
      </div>

      <div className="p-7 rounded-2xl text-white shadow-2xl mb-5" style={{ background: `linear-gradient(135deg, ${NAVY} 0%, ${ROYAL} 50%, ${CYAN} 100%)` }}>
        <div className="flex items-center gap-4">
          <div className="text-5xl">{topic.icon}</div>
          <div>
            <div className="text-[10px] uppercase tracking-[0.3em] font-bold text-blue-200 mb-1">Module</div>
            <div style={{ fontFamily: fontDisplay, letterSpacing: '-0.02em' }} className="text-3xl font-bold">{topic.title}</div>
          </div>
        </div>
        <div className="mt-4 text-sm text-blue-100 leading-relaxed">{topic.intro}</div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden mb-4">
        <div style={{ background: `linear-gradient(90deg, ${NAVY} 0%, #1A3568 100%)` }} className="px-6 py-3 text-white">
          <div style={{ fontFamily: fontDisplay }} className="text-lg font-bold">Core Concepts</div>
        </div>
        <div className="p-4 space-y-2">
          {topic.points.map((p, i) => (
            <div key={i} className="flex items-start gap-3 p-3 rounded-xl hover:bg-slate-50 transition">
              <div style={{ background: ICE, color: NAVY }} className="w-7 h-7 rounded-lg flex items-center justify-center font-bold text-xs flex-shrink-0">
                {i + 1}
              </div>
              <div>
                <div className="font-bold text-sm text-slate-800">{p.h}</div>
                <div className="text-xs text-slate-600 mt-1 leading-relaxed">{p.t}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="px-5 py-3 border-b border-slate-200" style={{ background: ICE }}>
          <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-base font-bold">🔗 Official IRS Resources</div>
          <div className="text-xs text-slate-600 mt-0.5">Bookmark these. They are the source of truth.</div>
        </div>
        <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-2">
          {topic.links.map((l, i) => (
            <a key={i} href={l.url} target="_blank" rel="noopener noreferrer"
              className="flex items-center gap-2 p-3 rounded-xl hover:bg-slate-50 transition border border-slate-100 group">
              <ExternalLink size={14} style={{ color: ROYAL }} className="flex-shrink-0" />
              <span className="text-sm font-semibold flex-1" style={{ color: NAVY }}>{l.label}</span>
              <ChevronRight size={14} className="text-slate-400 group-hover:text-blue-500 transition" />
            </a>
          ))}
        </div>
      </div>
    </div>
  );
}


