function MonthlyWorkflow() {
  const [active, setActive] = useState(0);
  return (
    <div>
      <SectionHead eyebrow="Daily & Month-End · Tool" title="Monthly Bookkeeping Workflow · Day-by-Day Timeline" desc="The exact day-by-day rhythm that takes you from chaos to consistent. Run this every month and you'll close on the 10th — not the 25th. Predictable workflow = predictable income." />

      <div style={{ background: SHEEN }} className="glass-card p-5 rounded-2xl mt-6 mb-5">
        <div className="flex gap-3 items-start">
          <CalendarClock size={20} style={{ color: ROYAL }} className="flex-shrink-0 mt-0.5" />
          <div className="text-sm text-slate-700 leading-relaxed">
            <span className="font-bold" style={{ color: NAVY }}>Why this matters:</span> Most bookkeepers close on the 20th-25th because they have no rhythm — they react. This timeline lets you close on the 10th by working backwards from the deadline. Closing early = more time for advisory = higher rates.
          </div>
        </div>
      </div>

      <div className="mb-6 p-5 rounded-2xl bg-white border border-slate-200 shadow-sm">
        <div className="text-[10px] uppercase tracking-[0.2em] font-bold mb-3" style={{ color: ROYAL }}>Visual Timeline · Click any phase to expand</div>
        <div className="flex gap-1 overflow-x-auto pb-2">
          {MONTHLY_WORKFLOW.map((p, i) => (
            <button key={i} onClick={() => setActive(i)}
              className={`flex-1 min-w-[100px] p-3 rounded-xl transition text-left ${active === i ? 'shadow-lg' : 'opacity-60 hover:opacity-100'}`}
              style={{ background: active === i ? `linear-gradient(135deg, ${p.color} 0%, ${p.color}CC 100%)` : `${p.color}15`, color: active === i ? 'white' : p.color }}>
              <div className="text-[10px] font-bold uppercase tracking-wider mb-1">{p.range}</div>
              <div className="text-xs font-bold leading-tight">{p.label}</div>
            </button>
          ))}
        </div>
      </div>

      {(() => {
        const p = MONTHLY_WORKFLOW[active];
        return (
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="px-6 py-4 text-white" style={{ background: `linear-gradient(135deg, ${p.color} 0%, ${p.color}CC 100%)` }}>
              <div className="text-[10px] uppercase tracking-[0.3em] font-bold text-white/80">{p.range} of the month</div>
              <div style={{ fontFamily: fontDisplay, letterSpacing: '-0.01em' }} className="text-2xl font-bold mt-1">{p.label}</div>
            </div>
            <div className="p-4 space-y-2">
              {p.tasks.map((t, i) => (
                <div key={i} className="p-4 rounded-xl border border-slate-100" style={{ background: '#FAFCFF' }}>
                  <div className="flex items-start gap-3">
                    <span className="text-[10px] font-bold tracking-wider px-2 py-1 rounded-lg flex-shrink-0 mt-0.5" style={{ background: ICE, color: NAVY }}>
                      {t.time}
                    </span>
                    <div className="flex-1">
                      <div className="font-bold text-sm text-slate-800">{t.task}</div>
                      <div className="text-xs text-slate-600 mt-1 leading-relaxed">{t.detail}</div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      })()}

      <div className="mt-6 bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="px-5 py-3 border-b border-slate-200" style={{ background: ICE }}>
          <div style={{ fontFamily: fontDisplay, color: NAVY }} className="text-base font-bold">📋 Full Timeline at a Glance</div>
        </div>
        <div className="p-4">
          {MONTHLY_WORKFLOW.map((p, i) => (
            <div key={i} className="flex items-start gap-4 py-2 border-b border-slate-100 last:border-0">
              <div className="w-24 flex-shrink-0">
                <div className="text-xs font-bold" style={{ color: p.color }}>{p.range}</div>
              </div>
              <div className="flex-1">
                <div className="font-bold text-sm text-slate-800">{p.label}</div>
                <div className="text-xs text-slate-600 mt-0.5">{p.tasks.length} tasks</div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

